  // ════════════════════════════════════════════════════════════
  // SECTION 5: Interactive Element Stress Testing
  // ════════════════════════════════════════════════════════════

  test('all safe buttons are clickable without crash', async ({ page }) => {
    const errors = collectConsoleErrors(page);
    await navigateToPage(page);
    const buttons = page.locator('button:visible');
    const count = await buttons.count();
    for (let i = 0; i < count; i++) {
      const btn = buttons.nth(i);
      const text = (await btn.textContent() || '').trim();
      const ariaLabel = (await btn.getAttribute('aria-label')) || '';
      const combined = `${text} ${ariaLabel}`;
      if (BUTTON_DENYLIST.test(combined)) continue;
      if (await btn.isDisabled()) continue;
      try {
        await btn.click({ timeout: 3000 });
        await page.waitForTimeout(300);
      } catch { /* navigated or dialog opened */ }
      await expect(page.locator('body')).toBeVisible();
      if (!page.url().includes('/business/business-help')) {
        await page.goto('/business/business-help');
        await waitForStable(page);
      }
    }
  });

  test('rapid clicking does not cause duplicate API calls', async ({ page }) => {
    let apiCallCount = 0;
    await page.route('**/api/**', async route => {
      apiCallCount++;
      await route.continue();
    });
    await page.goto('/business/business-help');
    await waitForStable(page);
    const refreshBtn = page.locator('button:visible').filter({
      hasText: /refresh|reload|retry/i
    }).first();
    if (await refreshBtn.isVisible({ timeout: 2000 }).catch(() => false)) {
      const callsBefore = apiCallCount;
      for (let i = 0; i < 5; i++) {
        await refreshBtn.click({ timeout: 500 }).catch(() => {});
      }
      await page.waitForTimeout(2000);
      await expect(page.locator('body')).toBeVisible();
      const callsAfter = apiCallCount - callsBefore;
      if (callsAfter >= 5) {
        console.warn(`Debounce concern: ${callsAfter} API calls from 5 rapid clicks`);
      }
    }
  });

