  test('interactive elements are reachable by keyboard (Tab)', async ({ page }) => {
    await navigateToPage(page);
    const focusedElements: string[] = [];
    for (let i = 0; i < 30; i++) {
      await page.keyboard.press('Tab');
      const focused = await page.evaluate(() => {
        const el = document.activeElement;
        if (!el || el === document.body) return null;
        return `${el.tagName.toLowerCase()}.${el.className?.toString().slice(0, 30) || ''}`;
      });
      if (focused) focusedElements.push(focused);
    }
    expect(focusedElements.length).toBeGreaterThan(0);
  });

  test('buttons and links have accessible names', async ({ page }) => {
    await navigateToPage(page);
    const buttons = page.locator('button:visible');
    const btnCount = await buttons.count();
    for (let i = 0; i < btnCount; i++) {
      const btn = buttons.nth(i);
      const text = (await btn.textContent() || '').trim();
      const ariaLabel = await btn.getAttribute('aria-label');
      const title = await btn.getAttribute('title');
      const hasName = text.length > 0 || (ariaLabel || '').length > 0 || (title || '').length > 0;
      if (!hasName) {
        const hasSVG = await btn.locator('svg').count() > 0;
        if (hasSVG) {
          console.warn(`Icon button without accessible name at index ${i}`);
        }
      }
    }
    const images = page.locator('img:visible');
    const imgCount = await images.count();
    for (let i = 0; i < imgCount; i++) {
      const alt = await images.nth(i).getAttribute('alt');
      expect(alt, `Image at index ${i} should have alt attribute`).not.toBeNull();
    }
  });

  test('focus states are visible on interactive elements', async ({ page }) => {
    await navigateToPage(page);
    await page.keyboard.press('Tab');
    await page.keyboard.press('Tab');
    const hasFocusRing = await page.evaluate(() => {
      const el = document.activeElement as HTMLElement;
      if (!el || el === document.body) return true;
      const style = window.getComputedStyle(el);
      return style.outline !== 'none' ||
        style.outlineStyle !== 'none' ||
        style.boxShadow !== 'none' ||
        el.classList.contains('focus-visible') ||
        el.matches(':focus-visible');
    });
    if (!hasFocusRing) {
      console.warn('Active element may lack visible focus indicator');
    }
  });

